{
  "mode": "method",
  "tests": [
    {
      "name": "basic_infusion",
      "input": ["track1.mp3", 10],
      "output": {"inclusion_percentage": 10, "listenability": true},
      "notes": "Tests a basic case of infusing gamma and theta frequencies at a low intensity."
    },
    {
      "name": "high_infusion",
      "input": ["track2.mp3", 50],
      "output": {"inclusion_percentage": 50, "listenability": true},
      "notes": "Tests the algorithm's ability to maintain listenability at a higher infusion percentage."
    },
    {
      "name": "zero_infusion",
      "input": ["track3.mp3", 0],
      "output": {"inclusion_percentage": 0, "listenability": true},
      "notes": "Edge case where no frequencies should be infused; should return 0% inclusion."
    },
    {
      "name": "full_infusion",
      "input": ["track4.mp3", 100],
      "output": {"inclusion_percentage": 100, "listenability": false},
      "notes": "Edge case where the track is fully infused; should be noticeable."
    },
    {
      "name": "silent_track",
      "input": ["silent.mp3", 10],
      "output": {"inclusion_percentage": 10, "listenability": true},
      "notes": "Tests the algorithm's handling of a silent track; should still return valid output."
    },
    {
      "name": "complex_track",
      "input": ["complex_track.mp3", 20],
      "output": {"inclusion_percentage": 20, "listenability": true},
      "notes": "Tests the algorithm's performance on a complex musical piece."
    },
    {
      "name": "long_track",
      "input": ["long_track.mp3", 15],
      "output": {"inclusion_percentage": 15, "listenability": true},
      "notes": "Tests the algorithm's efficiency on a longer track."
    },
    {
      "name": "multiple_tracks",
      "input": [["track5.mp3", 30], ["track6.mp3", 40]],
      "output": [{"inclusion_percentage": 30, "listenability": true}, {"inclusion_percentage": 40, "listenability": true}],
      "notes": "Tests the algorithm's ability to process multiple tracks in one call."
    }
  ],
  "assumptions": "The algorithm can handle various audio formats and lengths without performance degradation.",
  "notes": "Ensure that the listenability metric is accurately assessed through subjective listening tests."
}
